class Solution:
    def leastInterval(self, tasks: List[str], n: int) -> int:
        from collections import Counter
        freq = Counter(tasks)
        max_count = max(freq.values())
        num_max = sum(1 for v in freq.values() if v == max_count)
        return max(len(tasks), (max_count - 1) * (n + 1) + num_max)

