impl Solution {
    pub fn min_refuel_stops(target: i32, start_fuel: i32, mut stations: Vec<Vec<i32>>) -> i32 {
        let mut max_heap = BinaryHeap::new();
        let mut fuel = start_fuel;
        let mut stops = 0;
        let mut prev = 0;
        stations.push(vec![target, 0]);
        for station in &stations {
            fuel -= station[0] - prev;
            while let Some(f) = max_heap.peek() {
                if fuel >= 0 { break; }
                fuel += f;
                max_heap.pop();
                stops += 1;
            }
            if fuel < 0 {
                return -1;
            }
            max_heap.push(station[1]);
            prev = station[0];
        }
        stops
    }
}

